on conflict (id) do update set
  name = excluded.name,
  price_per_m2 = excluded.price_per_m2,
  base_cost_per_m2 = excluded.base_cost_per_m2,
  base_minimum_sale_per_m2 = excluded.base_minimum_sale_per_m2,
  margin_percentage = excluded.margin_percentage,
  provider = excluded.provider,
  category = excluded.category,
  material_line = excluded.material_line,
  material_type = excluded.material_type,
  thickness_label = excluded.thickness_label,
  texture = excluded.texture,
  image_url = excluded.image_url,
  active = excluded.active,
  source_inventory_id = excluded.source_inventory_id,
  created_at = excluded.created_at,
  updated_at = excluded.updated_at;
